@page "/catalog"
@using sv_ebb280ee4dc4470b9f8fbc75b6e81765.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<div class="catalog-container">
    <!-- Left Sidebar -->
    <aside class="catalog-sidebar">
        <h3>Filters</h3>

        @if (categories is not null)
        {
            <div class="filter-section">
                <h4>Categories</h4>
                @foreach (var category in categories)
                {
                    <label class="filter-checkbox">
                        <input type="checkbox"
                               checked="@selectedCategories.Contains(category)"
                               @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                        @category
                    </label>
                }
            </div>
        }

        <div class="filter-section">
            <h4>Price Range</h4>
            <div class="price-inputs">
                <input type="number" placeholder="Min" @bind="minPrice" min="0" step="0.01" />
                <span>–</span>
                <input type="number" placeholder="Max" @bind="maxPrice" min="0" step="0.01" />
            </div>
        </div>

        <div class="filter-section">
            <label class="filter-checkbox">
                <input type="checkbox" @bind="inStockOnly" />
                In Stock Only
            </label>
        </div>

        <div class="filter-actions">
            <button class="btn btn-primary" @onclick="ApplyFilters">Apply Filters</button>
            <button class="btn btn-secondary" @onclick="ClearFilters">Clear Filters</button>
        </div>
    </aside>

    <!-- Main Content -->
    <main class="catalog-main">
        @if (isLoading)
        {
            <div class="catalog-status">
                <p>Loading products...</p>
            </div>
        }
        else if (errorMessage is not null)
        {
            <div class="catalog-status catalog-error">
                <p>@errorMessage</p>
                <button class="btn btn-primary" @onclick="LoadProducts">Retry</button>
            </div>
        }
        else if (result is not null && result.Items.Count == 0)
        {
            <div class="catalog-status">
                <p>No products found matching your criteria.</p>
            </div>
        }
        else if (result is not null)
        {
            <!-- Toolbar -->
            <div class="catalog-toolbar">
                <div class="sort-control">
                    <label for="sortBy">Sort by:</label>
                    <select id="sortBy" @bind="sortBy" @bind:after="LoadProducts">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A-Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="showing-label">
                    Showing @((result.Page - 1) * result.PageSize + 1)–@(Math.Min(result.Page * result.PageSize, result.TotalCount)) of @result.TotalCount products
                </span>
            </div>

            <!-- Product Grid -->
            <div class="product-grid">
                @foreach (var product in result.Items)
                {
                    <ProductCard Product="product"
                                 OnProductClick="HandleProductClick"
                                 OnAddToCart="HandleAddToCart" />
                }
            </div>

            <!-- Pagination -->
            <div class="pagination">
                <button class="btn btn-page" disabled="@(result.Page <= 1)" @onclick="PreviousPage">Previous</button>
                @for (int i = 1; i <= TotalPages; i++)
                {
                    var pageNum = i;
                    <button class="btn btn-page @(pageNum == result.Page ? "active" : "")"
                            @onclick="() => GoToPage(pageNum)">
                        @pageNum
                    </button>
                }
                <button class="btn btn-page" disabled="@(result.Page >= TotalPages)" @onclick="NextPage">Next</button>
            </div>
        }
    </main>
</div>

@code {
    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 12;

    private PagedResult<Product>? result;
    private bool isLoading;
    private string? errorMessage;

    private int TotalPages => result is null || result.PageSize == 0
        ? 0
        : (int)Math.Ceiling((double)result.TotalCount / result.PageSize);

    [Parameter]
    public EventCallback<int> OnProductSelected { get; set; }

    protected override async Task OnInitializedAsync()
    {
        await LoadCategories();
        await LoadProducts();
    }

    private async Task LoadCategories()
    {
        try
        {
            categories = await ProductService.GetCategoriesAsync();
        }
        catch
        {
            categories = new List<string>();
        }
    }

    private async Task LoadProducts()
    {
        isLoading = true;
        errorMessage = null;
        StateHasChanged();

        try
        {
            var filter = new ProductFilter(
                Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
                MinPrice: minPrice,
                MaxPrice: maxPrice,
                InStockOnly: inStockOnly
            );

            result = await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load products: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await LoadProducts();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        await LoadProducts();
    }

    private async Task PreviousPage()
    {
        if (currentPage > 1)
        {
            currentPage--;
            await LoadProducts();
        }
    }

    private async Task NextPage()
    {
        if (currentPage < TotalPages)
        {
            currentPage++;
            await LoadProducts();
        }
    }

    private async Task GoToPage(int page)
    {
        currentPage = page;
        await LoadProducts();
    }

    private async Task HandleProductClick(Product product)
    {
        await OnProductSelected.InvokeAsync(product.Id);
    }

    private void HandleAddToCart(Product product)
    {
        // Add to cart logic would go here
    }
}

@using sv_ebb280ee4dc4470b9f8fbc75b6e81765.Services

<div class="product-card" @onclick="OnCardClick">
    <div class="product-image" title="@Product.Name">
        <span>@Product.Name</span>
    </div>
    <div class="product-info">
        <h4 class="product-name">@Product.Name</h4>
        <p class="product-price">@Product.Price.ToString("C")</p>
        <div class="product-rating">@GetStarRating(Product.Rating)</div>
        @if (!Product.InStock)
        {
            <span class="badge-out-of-stock">Out of Stock</span>
        }
        <button class="btn btn-add-to-cart"
                disabled="@(!Product.InStock)"
                @onclick="OnAddToCartClick"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnProductClick { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task OnCardClick()
    {
        await OnProductClick.InvokeAsync(Product);
    }

    private async Task OnAddToCartClick()
    {
        await OnAddToCart.InvokeAsync(Product);
    }

    private static string GetStarRating(double rating)
    {
        int fullStars = (int)Math.Round(rating);
        int emptyStars = 5 - fullStars;
        return new string('★', fullStars) + new string('☆', emptyStars);
    }
}

namespace sv_ebb280ee4dc4470b9f8fbc75b6e81765.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

.catalog-container {
    display: flex;
    gap: 1.5rem;
    padding: 1rem;
}

.catalog-sidebar {
    width: 25%;
    min-width: 220px;
    padding: 1rem;
    border-right: 1px solid #e0e0e0;
}

.catalog-sidebar h3 {
    margin-top: 0;
}

.filter-section {
    margin-bottom: 1.25rem;
}

.filter-section h4 {
    margin-bottom: 0.5rem;
}

.filter-checkbox {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    margin-bottom: 0.3rem;
    cursor: pointer;
}

.price-inputs {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.price-inputs input {
    width: 80px;
    padding: 0.3rem;
}

.filter-actions {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    margin-top: 1rem;
}

.catalog-main {
    width: 75%;
    flex: 1;
}

.catalog-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1rem;
    padding: 0.5rem 0;
    border-bottom: 1px solid #e0e0e0;
}

.sort-control {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.sort-control select {
    padding: 0.3rem 0.5rem;
}

.showing-label {
    color: #666;
    font-size: 0.9rem;
}

.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 1.25rem;
    margin-bottom: 1.5rem;
}

.pagination {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 0.4rem;
    padding: 1rem 0;
}

.btn {
    padding: 0.5rem 1rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.9rem;
}

.btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.btn-primary {
    background: #0d6efd;
    color: white;
    border-color: #0d6efd;
}

.btn-secondary {
    background: #6c757d;
    color: white;
    border-color: #6c757d;
}

.btn-page {
    min-width: 2.2rem;
    text-align: center;
    background: white;
}

.btn-page.active {
    background: #0d6efd;
    color: white;
    border-color: #0d6efd;
}

.catalog-status {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 3rem 1rem;
    color: #666;
}

.catalog-error {
    color: #dc3545;
}

::deep .product-card {
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    overflow: hidden;
    cursor: pointer;
    transition: box-shadow 0.2s;
}

::deep .product-card:hover {
    box-shadow: 0 2px 12px rgba(0, 0, 0, 0.12);
}

::deep .product-image {
    background: #f0f0f0;
    height: 160px;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #999;
    font-size: 0.85rem;
    text-align: center;
    padding: 0.5rem;
}

::deep .product-info {
    padding: 0.75rem;
}

::deep .product-name {
    margin: 0 0 0.3rem;
    font-size: 1rem;
}

::deep .product-price {
    margin: 0 0 0.3rem;
    font-weight: bold;
    color: #2a7d2a;
}

::deep .product-rating {
    color: #f5a623;
    margin-bottom: 0.4rem;
}

::deep .badge-out-of-stock {
    display: inline-block;
    background: #dc3545;
    color: white;
    font-size: 0.75rem;
    padding: 0.15rem 0.5rem;
    border-radius: 3px;
    margin-bottom: 0.4rem;
}

::deep .btn-add-to-cart {
    width: 100%;
    padding: 0.5rem;
    background: #198754;
    color: white;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    margin-top: 0.4rem;
}

::deep .btn-add-to-cart:disabled {
    background: #ccc;
    cursor: not-allowed;
}

