.catalog-container {
    display: flex;
    gap: 1.5rem;
    padding: 1rem;
}

.catalog-sidebar {
    width: 25%;
    min-width: 220px;
    padding: 1rem;
    border-right: 1px solid #e0e0e0;
}

.catalog-sidebar h3 {
    margin-top: 0;
}

.filter-section {
    margin-bottom: 1.25rem;
}

.filter-section h4 {
    margin-bottom: 0.5rem;
}

.filter-checkbox {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    margin-bottom: 0.3rem;
    cursor: pointer;
}

.price-inputs {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.price-inputs input {
    width: 80px;
    padding: 0.3rem;
}

.filter-actions {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    margin-top: 1rem;
}

.catalog-main {
